const cfg = $input.item.json;

const required = [
  'githubRepo',
  'maxPrsPerRun',
  'lookbackHours',
  'routerRulesJson',
  'reviewerPromptTemplatesJson'
];

const missing = required.filter((key) => {
  const value = cfg[key];
  return value == null || String(value).trim() === '' || String(value).startsWith('REPLACE_WITH_');
});

if (missing.length) {
  throw new Error(`Config placeholders or missing values: ${missing.join(', ')}`);
}

if (!/^[^\s/]+\/[^\s/]+$/.test(String(cfg.githubRepo))) {
  throw new Error('githubRepo must use owner/repo format');
}

const maxPrsPerRun = Number(cfg.maxPrsPerRun);
if (!Number.isFinite(maxPrsPerRun) || maxPrsPerRun < 1 || maxPrsPerRun > 100) {
  throw new Error('maxPrsPerRun must be between 1 and 100');
}

const lookbackHours = Number(cfg.lookbackHours);
if (!Number.isFinite(lookbackHours) || lookbackHours < 1 || lookbackHours > 720) {
  throw new Error('lookbackHours must be between 1 and 720');
}

let routerRules;
let reviewerPromptTemplates;

try {
  routerRules = JSON.parse(cfg.routerRulesJson);
} catch (error) {
  throw new Error(`Invalid routerRulesJson: ${error.message}`);
}

try {
  reviewerPromptTemplates = JSON.parse(cfg.reviewerPromptTemplatesJson);
} catch (error) {
  throw new Error(`Invalid reviewerPromptTemplatesJson: ${error.message}`);
}

const requiredRoles = ['ci_cd', 'security', 'tests', 'architecture', 'docs'];
for (const role of requiredRoles) {
  if (!routerRules[role]) throw new Error(`Missing router rule for role: ${role}`);
  if (!reviewerPromptTemplates[role]) throw new Error(`Missing prompt template for role: ${role}`);
}

return [{
  json: {
    ...cfg,
    maxPrsPerRun,
    lookbackHours,
    routerRules,
    reviewerPromptTemplates
  }
}];

const cfg = $input.item.json;
const state = $getWorkflowStaticData('global');
const now = new Date();
const fallbackSince = new Date(now.getTime() - (cfg.lookbackHours * 60 * 60 * 1000));
const previous = typeof state.lastSuccessfulRunAt === 'string' ? new Date(state.lastSuccessfulRunAt) : null;
const sinceDate = previous && Number.isFinite(previous.getTime()) ? previous : fallbackSince;

return [{
  json: {
    ...cfg,
    runId: `pr-review-${now.toISOString().replace(/[:.]/g, '-')}`,
    runStartedAt: now.toISOString(),
    since: sinceDate.toISOString(),
    previousCursor: state.lastSuccessfulRunAt ?? null
  }
}];

const cfg = $input.item.json;
const command = [
  'gh pr list',
  `--repo ${cfg.githubRepo}`,
  '--state open',
  `--limit ${cfg.maxPrsPerRun}`,
  '--json number,title,url,updatedAt,isDraft,labels,headRefOid,baseRefName,headRefName'
].join(' ');

return [{ json: { ...cfg, command } }];

const cfg = $('Build PR List Command').first().json;
const raw = $input.item.json.stdout ?? '[]';
let rows;

try {
  rows = JSON.parse(raw);
} catch (error) {
  throw new Error(`Unable to parse gh pr list JSON: ${error.message}`);
}

if (!Array.isArray(rows)) rows = [];

const sinceMs = Date.parse(cfg.since);
const filtered = rows.filter((pr) => {
  const updatedMs = Date.parse(pr.updatedAt || 0);
  if (!Number.isFinite(updatedMs)) return false;
  if (!cfg.includeDraftPrs && pr.isDraft) return false;
  return updatedMs >= sinceMs;
});

return filtered.map((pr) => ({
  json: {
    ...cfg,
    prNumber: pr.number,
    prTitle: pr.title,
    prUrl: pr.url,
    prUpdatedAt: pr.updatedAt,
    prHeadSha: pr.headRefOid ?? null,
    prBaseRef: pr.baseRefName ?? null,
    prHeadRef: pr.headRefName ?? null,
    prLabels: Array.isArray(pr.labels) ? pr.labels.map((l) => l.name).filter(Boolean) : []
  }
}));

const item = $input.item.json;
const command = [
  'gh pr view',
  String(item.prNumber),
  `--repo ${item.githubRepo}`,
  '--json number,title,url,updatedAt,isDraft,labels,headRefOid,baseRefName,headRefName,files'
].join(' ');

return [{ json: { ...item, command } }];

const cfg = $('Build PR Detail Command').item.json;
const raw = $input.item.json.stdout ?? '{}';
let pr;

try {
  pr = JSON.parse(raw);
} catch (error) {
  throw new Error(`Unable to parse gh pr view JSON for PR ${cfg.prNumber}: ${error.message}`);
}

const labels = Array.isArray(pr.labels) ? pr.labels.map((l) => String(l.name || '').toLowerCase()).filter(Boolean) : [];
const files = Array.isArray(pr.files) ? pr.files.map((f) => String(f.path || '')).filter(Boolean) : [];

const hasPathMatch = (patterns) => {
  const arr = Array.isArray(patterns) ? patterns : [];
  return arr.some((pattern) => {
    try {
      const re = new RegExp(pattern);
      return files.some((file) => re.test(file));
    } catch (error) {
      return false;
    }
  });
};

const hasLabelMatch = (targets) => {
  const arr = Array.isArray(targets) ? targets : [];
  return arr.some((name) => labels.includes(String(name).toLowerCase()));
};

const roleOrder = ['ci_cd', 'security', 'tests', 'architecture', 'docs'];
const assignedRoles = [];

for (const role of roleOrder) {
  const rule = cfg.routerRules?.[role] ?? {};
  const match = hasPathMatch(rule.paths) || hasLabelMatch(rule.labels);
  if (match) assignedRoles.push(role);
}

if (!assignedRoles.length) {
  assignedRoles.push('architecture');
}

return [{
  json: {
    ...cfg,
    prNumber: pr.number ?? cfg.prNumber,
    prTitle: pr.title ?? cfg.prTitle,
    prUrl: pr.url ?? cfg.prUrl,
    prUpdatedAt: pr.updatedAt ?? cfg.prUpdatedAt,
    prHeadSha: pr.headRefOid ?? cfg.prHeadSha,
    prBaseRef: pr.baseRefName ?? cfg.prBaseRef,
    prHeadRef: pr.headRefName ?? cfg.prHeadRef,
    prLabels: labels,
    changedFiles: files,
    assignedRoles
  }
}];

const item = $input.item.json;
const out = [];

for (const role of item.assignedRoles || []) {
  const promptTemplate = item.reviewerPromptTemplates?.[role];
  if (!promptTemplate) continue;

  out.push({
    json: {
      ...item,
      reviewRole: role,
      promptTemplate
    }
  });
}

return out;

const src = $('Build Review Prompt').item.json;
const raw = $input.item.json.output ?? $input.item.json.response ?? $input.item.json.text ?? $input.item.json.result ?? '{}';
let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw.trim()) : raw;
} catch (error) {
  parsed = {
    schema_version: '1.0',
    run_id: src.runId,
    repo: src.githubRepo,
    pr_number: src.prNumber,
    pr_url: src.prUrl,
    pr_head_sha: src.prHeadSha,
    review_role: src.reviewRole,
    verdict: 'comment',
    overall_severity: 'medium',
    summary: `Reviewer output parse failure: ${error.message}`,
    findings: [
      {
        id: `${src.reviewRole}-parse-failure`,
        title: 'Reviewer output was not valid JSON',
        severity: 'medium',
        category: 'automation',
        file_path: null,
        line: null,
        rationale: String(raw).slice(0, 500),
        recommendation: 'Inspect agent output and re-run this PR review role.'
      }
    ],
    checks_ran: [],
    requires_follow_up: true,
    comment_markdown: null
  };
}

return [{
  json: {
    ...src,
    reviewResult: parsed
  }
}];

const items = $input.all();
if (!items.length) return [];

const grouped = new Map();

for (const item of items) {
  const row = item.json;
  const key = String(row.prNumber);
  if (!grouped.has(key)) {
    grouped.set(key, {
      runId: row.runId,
      repo: row.githubRepo,
      prNumber: row.prNumber,
      prTitle: row.prTitle,
      prUrl: row.prUrl,
      prUpdatedAt: row.prUpdatedAt,
      prHeadSha: row.prHeadSha,
      roles: []
    });
  }

  grouped.get(key).roles.push({
    role: row.reviewRole,
    result: row.reviewResult
  });
}

const outputs = [];

for (const group of grouped.values()) {
  const lines = [];
  lines.push(`Automated periodic review for #${group.prNumber} (${group.prTitle})`);
  lines.push('');
  lines.push(`PR: ${group.prUrl}`);
  lines.push(`Head SHA: ${group.prHeadSha ?? 'unknown'}`);
  lines.push('');
  lines.push('Reviewer summaries:');

  for (const roleData of group.roles) {
    const summary = roleData.result?.summary ?? 'No summary provided';
    const severity = roleData.result?.overall_severity ?? 'unknown';
    const verdict = roleData.result?.verdict ?? 'comment';
    const findings = Array.isArray(roleData.result?.findings) ? roleData.result.findings.length : 0;
    lines.push(`- ${roleData.role}: verdict=${verdict}, severity=${severity}, findings=${findings}`);
    lines.push(`  ${summary}`);
  }

  outputs.push({
    json: {
      runId: group.runId,
      repo: group.repo,
      prNumber: group.prNumber,
      prUpdatedAt: group.prUpdatedAt,
      commentBody: lines.join('\n'),
      roleResults: group.roles
    }
  });
}

return outputs;

const row = $input.item.json;
const shellQuote = (value) => `'${String(value).replace(/'/g, `'\''`)}'`;
const command = [
  'gh pr comment',
  String(row.prNumber),
  `--repo ${row.repo}`,
  '--body', shellQuote(row.commentBody)
].join(' ');

return [{ json: { ...row, command } }];

const outputs = $input.all().map((i) => i.json || {});
if (!outputs.length) return [];

let latest = null;
for (const row of outputs) {
  const value = row.prUpdatedAt ? Date.parse(row.prUpdatedAt) : NaN;
  if (!Number.isFinite(value)) continue;
  if (latest == null || value > latest) latest = value;
}

if (latest != null) {
  const state = $getWorkflowStaticData('global');
  state.lastSuccessfulRunAt = new Date(latest).toISOString();
}

return [{
  json: {
    processedPrCount: outputs.length,
    updatedCursorAt: latest == null ? null : new Date(latest).toISOString()
  }
}];
